(()=>{const STORAGE_KEY="principalDashboardActiveSection",SECTIONS=["mainContent","teachers","students","classes","subjects"];const viewport=()=>document.getElementById("dashboardViewport");const toArray=t=>Array.prototype.slice.call(t||[]);function safeGet(){try{return localStorage.getItem(STORAGE_KEY)}catch(e){return null}}function safeSet(v){try{localStorage.setItem(STORAGE_KEY,v)}catch(e){}}function hideAll(){SECTIONS.forEach(id=>{const el=document.getElementById(id);if(el)el.style.display="none"})}function highlight(sectionId){toArray(document.querySelectorAll('.nav-link[data-section]')).forEach(link=>{link.classList.toggle("active",link.getAttribute("data-section")===sectionId)})}function showSection(id,opt){const settings=Object.assign({save:true,scroll:true},opt||{});const targetId=SECTIONS.includes(id)?id:"mainContent";hideAll();const target=document.getElementById(targetId);if(target)target.style.display="block";highlight(targetId);if(settings.save)safeSet(targetId);if(settings.scroll){const pane=viewport();if(pane){pane.scrollTo({top:0,behavior:"smooth"})}}}function bindSectionTriggers(){toArray(document.querySelectorAll("[data-section]")).forEach(trigger=>{trigger.addEventListener("click",e=>{const id=trigger.getAttribute("data-section");if(!id)return;if(trigger.tagName.toLowerCase()==="a")e.preventDefault();showSection(id)})})}function bindFeatureKeyboard(){toArray(document.querySelectorAll('.feature-card[data-section]')).forEach(card=>{card.addEventListener("keydown",e=>{if(e.key==="Enter"||e.key===" "){e.preventDefault();showSection(card.getAttribute("data-section"))}})})}function bindProfileModal(){window.openProfile=function(){const modalEl=document.getElementById("profileModal");if(!modalEl||typeof bootstrap==="undefined")return;new bootstrap.Modal(modalEl).show()}}function bindTeacherImageModal(){const imageModal=document.getElementById("imageModal");if(!imageModal)return;imageModal.addEventListener("show.bs.modal",event=>{const trigger=event.relatedTarget;if(!trigger)return;const image=trigger.getAttribute("data-image")||"";const name=trigger.getAttribute("data-name")||"Teacher Image";const email=trigger.getAttribute("data-email")||"";const modalImage=document.getElementById("teacherImageModalSrc");const modalTitle=document.getElementById("teacherImageLabel");const modalEmail=document.getElementById("teacherImageModalEmail");if(modalImage)modalImage.src=image;if(modalTitle)modalTitle.textContent=name;if(modalEmail)modalEmail.textContent=email});imageModal.addEventListener("hidden.bs.modal",()=>{const modalImage=document.getElementById("teacherImageModalSrc");const modalTitle=document.getElementById("teacherImageLabel");const modalEmail=document.getElementById("teacherImageModalEmail");if(modalImage)modalImage.src="";if(modalTitle)modalTitle.textContent="Teacher Image";if(modalEmail)modalEmail.textContent=""})}document.addEventListener("DOMContentLoaded",()=>{bindSectionTriggers();bindFeatureKeyboard();bindProfileModal();bindTeacherImageModal();showSection(safeGet()||"mainContent",{save:false,scroll:false});window.backHome=()=>showSection("mainContent");window.showTeachers=()=>showSection("teachers");window.showStudents=()=>showSection("students");window.showClasses=()=>showSection("classes");window.showSubjects=()=>showSection("subjects")})})();